    db.on('load', () => {
      // Destroy the write stream so any write attempt will fail
      const ws = (db as any)._writeStream;
      ws.destroy();

      // Wait for the stream to be fully destroyed
      ws.on('close', () => {
        let errorEmitted = false;

        db.on('error', () => {
          errorEmitted = true;
